protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: default discriminator property renamed from "Discriminator" to "$type".
        // Existing 500K documents use "Discriminator", and direct SQL queries reference c.Discriminator.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Existing documents have ids in "Product|123" format — preserve that.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // EF Core 9: HasIndex now throws for Cosmos entities (was silently ignored).
    // Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
    // Removed: modelBuilder.Entity<Product>().HasIndex(p => p.Sku);
}

